return-response.set-body:
@{
        var body = (JObject)context.Variables["reqBody"];
        var country = (string)(body["country"] ?? "dk");
        var citizen = (string)(body["citizenUpn"] ?? "anonymous");
        var certId = "ERASURE-" + country.ToUpper() + "-" + DateTime.UtcNow.ToString("yyyyMMddHHmmss") + "-" + Guid.NewGuid().ToString("N").Substring(0, 8).ToUpper();
        var eta = DateTime.UtcNow.AddDays(30).ToString("yyyy-MM-dd");
        var resp = new JObject {
          ["status"] = "accepted",
          ["certificateId"] = certId,
          ["estimatedCompletionDate"] = eta,
          ["country"] = country,
          ["citizenUpn"] = citizen,
          ["receivedAt"] = DateTime.UtcNow.ToString("o"),
          ["zones"] = new JArray("dataverse", "foundry-conversations", "appinsights", "blob-lake", "purview-lineage"),
          ["note"] = "Erasure cascade orchestrated by Microsoft Priva. Audit-only metadata required by law (GDPR art. 17(3)(b)/(e)) is retained."
        };
        return resp.ToString();
      }
